    20→    /** Create a new empty list of the given parameter type. */
    21→    @SuppressWarnings("unchecked")
    22→    static <T> GList<T> empty() {
    23→        return (GList<T>) Empty.SINGLETON;
    24→    }
    25→
    26→    /**
    27→     * Builder for making a list of elements.
    28→     *
    29→     * <p>Example: GList.of(1, 3, 5) is equivalent to
    30→     * GList&lt;Integer&gt;.empty().prepend(5).prepend(3).prepend(1).
    31→     */
    32→    @SafeVarargs
    33→    @SuppressWarnings("varargs")
    34→    static <T> GList<T> of(T... elems) {
    35→        return of(elems, 0);
    36→    }
    37→
    38→    /** Helper method for of(). */
    39→    private static <T> GList<T> of(T[] elems, int offset) {
    40→        if (elems.length <= offset) {
    41→            return empty();
    42→        } else {
    43→            return new Cons<>(elems[offset], of(elems, offset + 1));
    44→        }
    45→    }
    46→
    47→    /** Creates a list of <code>n</code> references to the value <code>elem</code>. */
    48→    static <T> GList<T> fill(int n, T elem) {
    49→        if (n <= 0) {
    50→            return empty();
    51→        } else {
    52→            return new Cons<>(elem, fill(n - 1, elem));
    53→        }
    54→
    55→        //    throw new RuntimeException("fill not implemented yet");
    56→    }
    57→
    58→    /** Returns the value of the first element in the list. */
    59→    T head();
    60→
    61→    /**
    62→     * Returns a new list equal to the old list without its head() element. If the list is empty, this
    63→     * will throw an exception.
    64→     */
    65→    GList<T> tail();
    66→
    67→    /** Returns a new list with the given value in the front. */
    68→    default GList<T> prepend(T val) {
    69→        return new Cons<>(val, this);
    70→    }
    71→
    72→    /** Computes the number of elements in the list. */
    73→    int length();
    74→
    75→    /** Returns whether the list is empty or not. */
    76→    boolean isEmpty();
