 1→package edu.rice.comp322.provided.streams.provided;
 2→
 3→import edu.rice.comp322.provided.streams.models.Customer;
 4→import edu.rice.comp322.provided.streams.models.Product;
 5→
 6→/**
 7→ * The discount object helps you calculate the optimal discounts on a product which a
 8→ * given customer can achieve.
 9→ */
10→public class DiscountObject {
11→
12→    public Customer purchaser;
13→
14→    public Product product;
15→
16→    public Double truePrice;
17→
18→    public Double fullPrice;
19→
20→    public Double discount;
21→
22→    /**
23→     * Constructor for a discount object. A discount object is used to help determine
24→     * things like how much a customer will pay for a specific product, which is then
25→     * used to calculate discount.
26→     */
27→    public DiscountObject(Customer purchaser, Product product) {
28→        this.purchaser = purchaser;
29→        this.product = product;
30→
31→        /*
32→         * Do not assume any sales prices are better than original by default.
33→         */
34→        Double bestPrice = this.product.getFullPrice();
35→
36→        // If a is sale running
37→        if (this.product.getSalePrice() != null && this.product.getSalePrice() < this.product.getFullPrice()) {
38→            bestPrice = this.product.getSalePrice();
39→        }
40→
41→        // If a user has a tier and the product has a price for that tier
42→        if (this.purchaser.getTier() == 1 &&
43→            this.product.getTierOnePrice() != null &&
44→            this.product.getTierOnePrice() < this.product.getFullPrice()) {
45→            bestPrice = this.product.getTierOnePrice();
46→        } else if (this.purchaser.getTier() == 2 &&
47→            this.product.getTierTwoPrice() != null &&
48→            this.product.getTierTwoPrice() < this.product.getFullPrice()) {
49→            bestPrice = this.product.getTierTwoPrice();
50→        }
51→
52→
53→        this.truePrice = bestPrice;
54→        this.fullPrice = this.product.getFullPrice();
55→        this.discount = this.fullPrice - this.truePrice;
56→    }
57→
58→    public Double getFullPrice() {
59→        return this.fullPrice;
60→    }
61→
62→    public Double getPurchasedPrice() {
63→        return this.truePrice;
64→    }
65→
66→    public Double getDiscount() {
67→        return this.discount;
68→    }
69→
70→    public String toString() {
71→        return "" + this.purchaser.getName() + " purchased " + this.product.getName() +
72→            " with price " + this.truePrice + " with full item price " + this.fullPrice ;
73→    }
74→
75→}
