    // Problem 8: Map tier-0 customer IDs to sales utilization rate
    public static Map<Long, Double> problemEightSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
        return orderRepo.findAll().stream()
                .filter(o -> o.getCustomer().getTier() == 0)
                .flatMap(o -> o.getProducts().stream()
                        .map(p -> new DiscountObject(o.getCustomer(), p)))
                .collect(Collectors.groupingBy(
                        d -> d.purchaser.getId(),
                        Collectors.collectingAndThen(
                                Collectors.toList(),
                                list -> {
                                    double totalDiscount = list.stream().mapToDouble(DiscountObject::getDiscount).sum();
                                    double totalFullPrice = list.stream().mapToDouble(DiscountObject::getFullPrice).sum();
                                    return totalDiscount / totalFullPrice;
                                }
                        )
                ));
    }

